// Extract payload from Java app webhook call
const body = $input.first().json.body || $input.first().json;

const recipientEmail = body.recipientEmail || '';
const paperTitle     = body.paperTitle     || 'New Research Paper';
const paperDomain    = body.paperDomain    || 'Research';
const matchedKeyword = body.matchedKeyword || '';
const paperLink      = body.paperLink      || '';
const author         = body.author         || 'Unknown';

if (!recipientEmail) {
  throw new Error('No recipient email in payload');
}

return [{
  json: {
    recipientEmail,
    paperTitle,
    paperDomain,
    matchedKeyword,
    paperLink,
    author,
    subject: `[ResearchConnect] New paper in "${matchedKeyword}" — ${paperTitle}`,
    htmlBody: `
      <div style="font-family: Georgia, serif; max-width: 600px; margin: 0 auto; background: #0f1117; color: #e2e8f0; padding: 32px; border-radius: 12px;">
        <div style="border-bottom: 2px solid #6c9bff; padding-bottom: 16px; margin-bottom: 24px;">
          <h1 style="color: #6c9bff; font-size: 24px; margin: 0;">ResearchConnect</h1>
          <p style="color: #8892a4; margin: 4px 0 0;">Research Collaboration & Expert Recommendation</p>
        </div>

        <h2 style="color: #e2e8f0; font-size: 20px;">📄 New paper matches your followed keyword</h2>

        <div style="background: #1a1f2e; border-radius: 10px; padding: 20px; margin: 20px 0; border-left: 4px solid #6c9bff;">
          <p style="color: #8892a4; font-size: 12px; margin: 0 0 8px; text-transform: uppercase; letter-spacing: 1px;">Matched Keyword</p>
          <p style="color: #6c9bff; font-size: 16px; font-weight: bold; margin: 0;">${matchedKeyword}</p>
        </div>

        <div style="background: #1a1f2e; border-radius: 10px; padding: 20px; margin: 20px 0;">
          <h3 style="color: #e2e8f0; margin: 0 0 12px;">${paperTitle}</h3>
          <p style="color: #8892a4; margin: 4px 0;"><strong style="color: #a0aec0;">Author:</strong> ${author}</p>
          <p style="color: #8892a4; margin: 4px 0;"><strong style="color: #a0aec0;">Domain:</strong> ${paperDomain}</p>
          ${paperLink ? `<p style="margin: 12px 0 0;"><a href="${paperLink}" style="background: #6c9bff; color: white; padding: 8px 16px; border-radius: 6px; text-decoration: none; font-weight: bold;">View Paper →</a></p>` : ''}
        </div>

        <p style="color: #4a5568; font-size: 12px; margin-top: 32px; border-top: 1px solid #2d3748; padding-top: 16px;">
          You received this because you follow "${matchedKeyword}" in ResearchConnect.<br>
          Manage your notifications in the app under Collaborations → Following.
        </p>
      </div>
    `
  }
}];
